mapper.select:
SELECT point
FROM member
WHERE id = #{id}

mapper.update:
UPDATE
    member
SET
    point = point + #{amount}
WHERE
    id = #{id};

mapper.insert:
INSERT INTO member (
username, password, name, nickname, email, role, created_at
) VALUES ( #{username}, #{password}, #{name}, #{nickname}, #{email}, #{role}, NOW() )

mapper.update:
UPDATE member
name = #{name}, email = #{email}, image_url = #{imageUrl}, nickname = #{nickname},
WHERE id = #{id}

UPDATE MEMBER
SET name = #{name},
    nickname = #{nickname},
    status = #{status}
WHERE username = #{username}

mapper.select:
SELECT COUNT(*)
FROM member
WHERE nickname =#{nickname}

mapper.update:
UPDATE member
SET status = 'DELETED'
WHERE id = #{memberId}

mapper.select:
SELECT COUNT(*)
FROM auction a
WHERE a.seller_id = #{memberId}
  AND a.status = #{status}

SELECT id, nickname, email, status, created_at AS createdAt FROM member
role = 'USER'
AND ( nickname LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%') )
AND status = #{status}
ORDER BY created_at ${sortOrder}
